function looseEqual(left: unknown, right: unknown): boolean {
	if (left === right) return true;
	if ((left === null && right === undefined) || (left === undefined && right === null)) return true;
	if ((typeof left === "string" && typeof right === "number") || (typeof left === "number" && typeof right === "string")) return Number(left) === Number(right);
	if ((typeof left === "boolean" && (typeof right === "number" || typeof right === "string")) || (typeof right === "boolean" && (typeof left === "number" || typeof left === "string"))) return Number(left) === Number(right);
	return false;
}

function includesValue(container: unknown, value: unknown): boolean {
	if (Array.isArray(container)) return container.some((item) => looseEqual(item, value));
	return typeof container === "string" && typeof value === "string"
		? container.includes(value)
		: false;
}

function isRecord(value: unknown): value is Record<string, unknown> {
	return typeof value === "object" && value !== null && !Array.isArray(value);
}
